use std::num::ParseIntError;
use std::str::FromStr;

#[derive(Debug, PartialEq)]
struct Color {
    red: u8,
    green: u8,
    blue: u8,
}

impl FromStr for Color {
    type Err = String;

    fn from_str(s: &str) -> Result<Self, Self::Err> {
        let s = s.trim_start_matches('(').trim_end_matches(')');
        let parts: Vec<&str> = s.split(',').collect();
        if parts.len() != 3 {
            return Err(format!("Expected 3 color components, got {}", parts.len()));
        }
        let red = parts[0].parse::<u8>().map_err(|e| e.to_string())?;
        let green = parts[1].parse::<u8>().map_err(|e| e.to_string())?;
        let blue = parts[2].parse::<u8>().map_err(|e| e.to_string())?;
        Ok(Color { red, green, blue })
    }
}

fn main() {
    let c: Color = "(255,128,0)".parse().unwrap();
    println!("{:?}", c);
    assert_eq!(c, Color { red: 255, green: 128, blue: 0 });
}
